  timeRemaining: number // seconds
}

export default function TimerWidget({ timeRemaining }: TimerWidgetProps) {
  const minutes = Math.floor(timeRemaining / 60)
  const seconds = timeRemaining % 60
  const isUrgent = timeRemaining < 60

  const formatted = `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`

  return (
    <div
      className={`fixed top-6 left-6 flex items-center gap-3 px-6 py-3 rounded-2xl
        bg-white/5 backdrop-blur-md border
        ${isUrgent ? 'border-red-500/60 text-red-400 animate-pulse' : 'border-white/10 text-white'}`}
    >
      <Clock size={18} className="shrink-0" />
      <span className="font-mono text-xl font-semibold tracking-widest">{formatted}</span>
    </div>
  )
}

