interface GuiltGaugeWidgetProps {
  value: number // 0-100
}

export default function GuiltGaugeWidget({ value }: GuiltGaugeWidgetProps) {
  const clampedValue = Math.min(100, Math.max(0, value))

  // SVG arc parameters
  const size = 120
  const strokeWidth = 8
  const radius = (size - strokeWidth) / 2
  const circumference = Math.PI * radius // semi-circle arc length
  const dashOffset = circumference - (clampedValue / 100) * circumference

  // Color based on value
  const getColor = () => {
    if (clampedValue < 33) return '#22c55e' // green
    if (clampedValue < 66) return '#f97316' // orange
    return '#ef4444' // red
  }

  const color = getColor()

  return (
    <div className="fixed top-6 right-6 flex flex-col items-center gap-2 px-6 py-4 rounded-2xl bg-white/5 backdrop-blur-md border border-white/10">
      <span className="text-white/50 text-xs font-semibold tracking-widest uppercase">
        Culpabilité
      </span>

      <div className="relative" style={{ width: size, height: size / 2 + strokeWidth }}>
        <svg
          width={size}
          height={size / 2 + strokeWidth}
          style={{ filter: `drop-shadow(0 0 8px ${color})` }}
        >
          {/* Background arc */}
          <path
            d={`M ${strokeWidth / 2} ${size / 2} A ${radius} ${radius} 0 0 1 ${size - strokeWidth / 2} ${size / 2}`}
            fill="none"
            stroke="rgba(255,255,255,0.1)"
            strokeWidth={strokeWidth}
            strokeLinecap="round"
          />
          {/* Value arc */}
          <path
            d={`M ${strokeWidth / 2} ${size / 2} A ${radius} ${radius} 0 0 1 ${size - strokeWidth / 2} ${size / 2}`}
            fill="none"
            stroke={color}
            strokeWidth={strokeWidth}
            strokeLinecap="round"
            strokeDasharray={circumference}
            strokeDashoffset={dashOffset}
            style={{ transition: 'stroke-dashoffset 0.5s ease, stroke 0.5s ease' }}
          />
        </svg>

        {/* Center value */}
        <div className="absolute bottom-0 left-1/2 -translate-x-1/2 text-center">
          <span className="font-mono text-2xl font-bold" style={{ color }}>
            {clampedValue}
            <span className="text-sm font-normal">%</span>
          </span>
        </div>
      </div>
    </div>
  )
}

