import { useRef } from 'react'
import { Canvas } from '@react-three/fiber'
import { Float, ContactShadows, useGLTF } from '@react-three/drei'
import { EffectComposer, Bloom } from '@react-three/postprocessing'
import * as THREE from 'three'

function JudgePlaceholder() {
  return (
    <mesh position={[0, 0, 0]} castShadow>
      <capsuleGeometry args={[0.4, 1.2, 16, 32]} />
      <meshStandardMaterial color="#1a1a2e" metalness={0.3} roughness={0.6} />
    </mesh>
  )
}

function JudgeGLB({ modelPath }: { modelPath: string }) {
  const { scene } = useGLTF(modelPath)
  return <primitive object={scene} position={[0, -1, 0]} castShadow />
}

function FloatingGavel() {
  return (
    <Float speed={1.5} rotationIntensity={0.3} floatIntensity={0.5}>
      <group position={[-2, 0.5, -1]} rotation={[0.3, 0.8, 0.2]}>
        {/* Handle */}
        <mesh castShadow>
          <cylinderGeometry args={[0.04, 0.04, 0.8, 8]} />
          <meshStandardMaterial color="#5c3a1e" roughness={0.8} />
        </mesh>
        {/* Head */}
        <mesh position={[0, 0.5, 0]} castShadow>
          <boxGeometry args={[0.15, 0.25, 0.12]} />
          <meshStandardMaterial color="#3a2a14" metalness={0.2} roughness={0.6} />
        </mesh>
      </group>
    </Float>
  )
}

function FloatingDocument() {
  return (
    <Float speed={2} floatIntensity={0.8}>
      <mesh position={[2, 0.3, -0.5]} rotation={[0.1, -0.4, 0.15]} castShadow>
        <planeGeometry args={[0.5, 0.65]} />
        <meshStandardMaterial
          color="#e8e0d0"
          roughness={0.9}
          metalness={0}
          side={THREE.DoubleSide}
        />
      </mesh>
    </Float>
  )
}

const ORB_POSITIONS: [number, number, number][] = [
  [-1.5, 1.8, 0.5],
  [1.8, 1.2, -0.3],
  [-0.8, -1.2, 1],
  [1.2, -0.8, 0.8],
]

function LightOrbs() {
  return (
    <>
      {ORB_POSITIONS.map((pos, i) => (
        <mesh key={i} position={pos}>
          <sphereGeometry args={[0.08, 16, 16]} />
          <meshStandardMaterial emissive="#3366ff" emissiveIntensity={3} color="#000000" />
        </mesh>
      ))}
    </>
  )
}

interface Scene3DProps {
  modelPath?: string
}

export default function Scene3D({ modelPath }: Scene3DProps) {
  return (
    <Canvas
      gl={{ antialias: true }}
      shadows
      camera={{ fov: 45, position: [0, 0, 5] }}
      className="absolute inset-0"
    >
      {/* Lights */}
      <ambientLight intensity={0.2} />
      <directionalLight
        position={[2, 5, 2]}
        intensity={1.2}
        color="#ffffff"
        castShadow
        shadow-mapSize={[1024, 1024]}
      />
      <pointLight position={[-3, 2, 0]} intensity={0.8} color="#4444ff" />
      <pointLight position={[3, -1, 0]} intensity={0.5} color="#ff2200" />
      <spotLight
        position={[0, 6, 0]}
        intensity={2}
        angle={0.3}
        penumbra={0.5}
        color="#ffffff"
        castShadow
      />

      {/* Judge */}
      {modelPath ? <JudgeGLB modelPath={modelPath} /> : <JudgePlaceholder />}

      {/* Floating objects */}
      <FloatingGavel />
      <FloatingDocument />
      <LightOrbs />

      {/* Ground shadows */}
      <ContactShadows opacity={0.4} scale={6} blur={2} far={4} color="#000000" />

      {/* Post-processing */}
      <EffectComposer>
        <Bloom luminanceThreshold={0.2} luminanceSmoothing={0.9} height={300} intensity={0.8} />
      </EffectComposer>
    </Canvas>
  )
}

